module top_module(CLK, ALU_CTL, NUM1, NUM2, ZERO, ALU_RES);input CLK;
   input ALU_CTL;
   input [31:0] NUM1, NUM2;
   output 	ZERO;
   output [31:0] 	ALU_RES;

   assign ZERO = (ALU_RES == 0);
   assign ALU_RES = NUM1 + NUM2;  always @(*) begin
    if (1'b0) begin
      ZERO <= ~ALU_RES[31];
      ALU_RES <= NUM2 - NUM1;
    end
  end

endmodule
